const API = import.meta.env.VITE_API_URL || 'http://127.0.0.1:8000/api'
const STORAGE = API.replace(/\/api$/, '/storage')

async function api(path, options = {}) {
  const token = localStorage.getItem('nova_token')
  const headers = { Accept: 'application/json', ...(options.body instanceof FormData ? {} : { 'Content-Type': 'application/json' }), ...options.headers }
  if (token) headers.Authorization = `Bearer ${token}`
  let response
  try {
    response = await fetch(`${API}${path}`, { ...options, headers })
  } catch {
    throw new Error('Tidak dapat terhubung ke server. Pastikan layanan berjalan, lalu coba kembali.')
  }
  const type = response.headers.get('content-type') || ''
  let data
  if (type.includes('json')) {
    const raw = await response.text()
    const start = Math.min(...['{', '['].map(char => { const i = raw.indexOf(char); return i < 0 ? Infinity : i }))
    data = JSON.parse(start === Infinity ? raw : raw.slice(start))
  } else data = await response.blob()
  if (!response.ok) {
    const error = new Error(data.message || 'Terjadi kesalahan. Silakan coba lagi.')
    if (data.errors) {
      const messages = [...new Set(Object.values(data.errors).flat())]
      error.errors = {
        ...data.errors,
        general: [`Data belum dapat disimpan. ${messages.join(' ')}`],
      }
    } else {
      error.errors = { general: [error.message] }
    }
    error.status = response.status
    throw error
  }
  return data
}

const AuthContext = createContext(null)
const useAuth = () => useContext(AuthContext)
function AuthProvider({ children }) {
  const [user, setUser] = useState(() => JSON.parse(localStorage.getItem('nova_user') || 'null'))
  const login = async (email, password) => {
    const data = await api('/login', { method: 'POST', body: JSON.stringify({ email, password }) })
    localStorage.setItem('nova_token', data.token); localStorage.setItem('nova_user', JSON.stringify(data.user)); setUser(data.user)
    return data.user
  }
  const logout = async () => { try { await api('/logout', { method: 'POST' }) } catch {} localStorage.removeItem('nova_token'); localStorage.removeItem('nova_user'); setUser(null) }
  return <AuthContext.Provider value={{ user, login, logout }}>{children}</AuthContext.Provider>
}

const formatDate = d => {if(!d)return '-';const value=String(d);if(value.includes('|'))return value.split('|').map(x=>formatDate(x)).join(' – ');return new Intl.DateTimeFormat('id-ID',{day:'numeric',month:'short',year:'numeric'}).format(new Date(value.slice(0,10)))}
const formatDateTime = d => d?new Intl.DateTimeFormat('id-ID',{day:'numeric',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit'}).format(new Date(d)):'-'
const toDateTimeLocal = d => {if(!d)return '';const date=new Date(d),offset=date.getTimezoneOffset();return new Date(date.getTime()-offset*60000).toISOString().slice(0,16)}
const formatTimelineDate = entry => entry?.type==='range' ? `${formatDate(entry.start_date)} – ${formatDate(entry.end_date)}` : formatDate(entry?.date)
const money = n => Number(n) === 0 ? 'Gratis' : new Intl.NumberFormat('id-ID', { style:'currency', currency:'IDR', maximumFractionDigits:0 }).format(n)
