const Field=({label,error,children})=><label className="block"><span className="label">{label}</span>{children}{error&&<span className="mt-1 block text-xs font-bold text-rose-600">{error[0]}</span>}</label>
function Registration(){const {slug}=useParams(),[item,setItem]=useState(null),[errors,setErrors]=useState({}),[busy,setBusy]=useState(false),[ticket,setTicket]=useState('');useEffect(()=>{api(`/competitions/${slug}`).then(setItem)},[slug]);const submit=async e=>{e.preventDefault();setBusy(true);setErrors({});const form=new FormData(e.currentTarget);form.set('competition_id',item.id);form.set('consent',form.get('consent')?'1':'');try{const res=await api('/registrations',{method:'POST',body:form});setTicket(res.ticket_code);scrollTo(0,0)}catch(err){setErrors(err.errors||{general:[err.message]});scrollTo(0,0)}finally{setBusy(false)}};if(!item)return <Loader/>;if(ticket)return <section className="min-h-[75vh] px-5 py-16"><div className="mx-auto max-w-xl rounded-[34px] bg-white p-8 text-center shadow-xl"><div className="mx-auto grid size-20 place-items-center rounded-full bg-electric"><TicketCheck size={38}/></div><h1 className="mt-6 font-display text-3xl font-bold">Kamu resmi masuk arena!</h1><p className="mt-3 text-slate-500">Pendaftaranmu telah kami terima. Simpan kode tiket ini untuk memantau proses verifikasi.</p><div className="mt-7 rounded-2xl border-2 border-dashed border-slate-200 bg-slate-50 p-5"><div className="text-xs font-bold uppercase tracking-widest text-slate-400">Kode Tiket</div><div className="mt-2 font-display text-2xl font-bold tracking-wider">{ticket}</div></div><Link to="/lacak" className="btn-dark mt-7 w-full">Lacak Status <ArrowRight size={17}/></Link></div></section>;return <section className="px-5 py-10 lg:px-8"><div className="mx-auto max-w-4xl"><Link to={`/lomba/${slug}`} className="text-sm font-bold text-slate-500">← Kembali</Link><div className="mt-5"><div className="text-xs font-black uppercase tracking-[.2em] text-blue-600">Formulir pendaftaran</div><h1 className="mt-2 font-display text-3xl font-bold sm:text-5xl">Ambil tempatmu di arena.</h1><p className="mt-3 text-slate-500">{item.title} · {money(item.fee)}</p></div>{errors.general&&<div className="mt-6 rounded-2xl bg-rose-100 p-4 font-bold text-rose-700">{errors.general[0]}</div>}<form onSubmit={submit} className="mt-8 grid gap-6"><FormSection number="01" title="Data diri" text="Pastikan sesuai dokumen resmi."><div className="grid gap-5 sm:grid-cols-2"><Field label="Nama lengkap *" error={errors.full_name}><input className="input" name="full_name" required/></Field><Field label="NISN (10 digit) *" error={errors.nisn}><input className="input" name="nisn" inputMode="numeric" pattern="[0-9]{10}" maxLength="10" required/></Field><Field label="Email aktif *" error={errors.email}><input className="input" name="email" type="email" required/></Field><Field label="Nomor WhatsApp *" error={errors.whatsapp}><input className="input" name="whatsapp" inputMode="tel" required/></Field><Field label="Tempat lahir *" error={errors.birth_place}><input className="input" name="birth_place" required/></Field><Field label="Tanggal lahir *" error={errors.birth_date}><input className="input" name="birth_date" type="date" required/></Field><Field label="Kelas *" error={errors.grade}><select className="input" name="grade" required><option value="">Pilih kelas</option><option>X</option><option>XI</option><option>XII</option></select></Field><Field label="Nama ibu kandung *" error={errors.mother_name}><input className="input" name="mother_name" required/><span className="mt-1 flex items-center gap-1 text-[11px] text-slate-400"><LockKeyhole size={11}/>Terenkripsi dan tidak terlihat oleh PIC.</span></Field></div></FormSection><FormSection number="02" title="Sekolah & tim" text="Informasi untuk validasi delegasi."><div className="grid gap-5 sm:grid-cols-2"><Field label="Asal sekolah *" error={errors.school_name}><input className="input" name="school_name" required/></Field><Field label="Nama guru pendamping *" error={errors.teacher_name}><input className="input" name="teacher_name" required/></Field><Field label="Kontak guru *" error={errors.teacher_contact}><input className="input" name="teacher_contact" inputMode="tel" required/></Field><Field label="Kode sekolah (opsional)" error={errors.school_code}><input className="input" name="school_code" placeholder="Untuk jalur undangan"/></Field><Field label="Nama tim (opsional)" error={errors.team_name}><input className="input" name="team_name"/></Field><Field label="Kategori peserta (opsional)" error={errors.participant_category}><input className="input" name="participant_category" placeholder="Contoh: Individu / Beregu"/></Field></div></FormSection><FormSection number="03" title="Dokumen verifikasi" text="JPG, PNG, atau PDF maksimal 2 MB per file."><div className="grid gap-5 sm:grid-cols-2"><FileInput name="student_card" label="Kartu pelajar aktif *" accept=".jpg,.jpeg,.png,.pdf" error={errors.student_card}/><FileInput name="delegation_letter" label="Surat delegasi resmi *" accept=".jpg,.jpeg,.png,.pdf" error={errors.delegation_letter}/><FileInput name="photo" label="Pas foto resmi *" accept=".jpg,.jpeg,.png" error={errors.photo}/>{Number(item.fee)>0&&<FileInput name="payment_proof" label="Bukti pembayaran" accept=".jpg,.jpeg,.png,.pdf" error={errors.payment_proof}/>}</div></FormSection><div className="rounded-3xl bg-ink p-6 text-white"><label className="flex cursor-pointer items-start gap-3"><input type="checkbox" name="consent" required className="mt-1 size-5 accent-[#b8ff2c]"/><span className="text-sm leading-6 text-slate-300">Saya menyetujui penggunaan data untuk proses pendaftaran dan verifikasi. Saya memahami data sensitif dijaga kerahasiaannya sesuai kebijakan privasi.</span></label><button disabled={busy} className="btn-primary mt-6 w-full py-4 disabled:opacity-60">{busy?'Mengirim pendaftaran...':'Kirim Pendaftaran'} {!busy&&<ArrowRight size={18}/>}</button></div></form></div></section>}
function FormSection({number,title,text,children}){return <section className="rounded-[28px] bg-white p-5 sm:p-8"><div className="mb-7 flex gap-4"><div className="font-display text-3xl font-bold text-blue-600">{number}</div><div><h2 className="font-display text-xl font-bold">{title}</h2><p className="mt-1 text-sm text-slate-500">{text}</p></div></div>{children}</section>}
function FileInput({name,label,accept,error}){const [file,setFile]=useState('');return <Field label={label} error={error}><label className="flex min-h-28 cursor-pointer flex-col items-center justify-center rounded-2xl border-2 border-dashed border-slate-200 bg-slate-50 p-4 text-center hover:border-ink"><UploadCloud size={22}/><span className="mt-2 max-w-full truncate text-sm font-bold">{file||'Pilih atau ambil foto'}</span><span className="mt-1 text-[11px] text-slate-400">Maks. 2 MB</span><input hidden type="file" name={name} accept={accept} required={!name.includes('payment')} onChange={e=>setFile(e.target.files?.[0]?.name||'')}/></label></Field>}

function Track(){const [code,setCode]=useState(''),[email,setEmail]=useState(''),[data,setData]=useState(null),[error,setError]=useState(''),[busy,setBusy]=useState(false);const go=async e=>{e.preventDefault();setBusy(true);setError('');setData(null);try{setData(await api(`/track/${code}?email=${encodeURIComponent(email)}`))}catch{setError('Kode tiket atau email tidak ditemukan.')}finally{setBusy(false)}};return <section className="min-h-[75vh] px-5 py-14"><div className="mx-auto max-w-3xl"><div className="text-center"><div className="mx-auto grid size-14 place-items-center rounded-2xl bg-electric"><TicketCheck/></div><h1 className="mt-5 font-display text-4xl font-bold">Lacak pendaftaranmu</h1><p className="mt-3 text-slate-500">Masukkan kode tiket dan email yang digunakan saat mendaftar.</p></div><form onSubmit={go} className="mx-auto mt-8 grid max-w-xl gap-4 rounded-3xl bg-white p-5 sm:grid-cols-[1fr_1fr_auto]"><input className="input" placeholder="NOVA-XXXXXXXX" value={code} onChange={e=>setCode(e.target.value.toUpperCase())} required/><input className="input" type="email" placeholder="Email pendaftar" value={email} onChange={e=>setEmail(e.target.value)} required/><button className="btn-dark" disabled={busy}>{busy?'...':'Lacak'}</button></form>{error&&<div className="mx-auto mt-5 max-w-xl rounded-2xl bg-rose-100 p-4 text-center font-bold text-rose-700">{error}</div>}{data&&<div className="mx-auto mt-8 max-w-xl overflow-hidden rounded-[30px] bg-white shadow-xl"><div className="bg-ink p-6 text-white"><div className="flex items-center justify-between"><span className="text-xs font-bold uppercase tracking-widest text-slate-400">{data.ticket_code}</span><Status value={data.status}/></div><h2 className="mt-4 font-display text-2xl font-bold">{data.competition.title}</h2><p className="mt-1 text-sm text-slate-400">{data.full_name} · {data.school_name}</p></div><div className="p-6"><div className="relative grid grid-cols-3 text-center text-xs font-bold"><div className="absolute left-[16%] right-[16%] top-4 h-0.5 bg-slate-200"/><Step active icon={<Check size={15}/>} label="Terkirim"/><Step active={data.status!=='pending'} icon={<ClipboardCheck size={15}/>} label="Diverifikasi"/><Step active={data.status==='approved'} danger={data.status==='rejected'} icon={<Award size={15}/>} label="Hasil"/></div>{data.review_note&&<div className="mt-7 rounded-2xl bg-violet-50 p-4"><div className="text-xs font-bold uppercase tracking-wider text-violet-600">Catatan verifikator</div><p className="mt-1 text-sm leading-6">{data.review_note}</p></div>}<div className="mt-7 flex items-center justify-between border-t pt-5 text-sm"><span className="text-slate-500">Tanggal kompetisi</span><b>{formatDate(data.competition.event_date)}</b></div></div></div>}</div></section>}
function Step({active,danger,icon,label}){return <div className="relative z-10 flex flex-col items-center gap-2"><span className={`grid size-8 place-items-center rounded-full ${danger?'bg-rose-500 text-white':active?'bg-electric text-ink':'bg-slate-200 text-slate-400'}`}>{icon}</span><span>{label}</span></div>}

function Login(){const {user,login}=useAuth(),nav=useNavigate(),[email,setEmail]=useState('admin@kreasiunm.id'),[password,setPassword]=useState('password123'),[error,setError]=useState(''),[busy,setBusy]=useState(false);if(user)return <Navigate to="/panel"/>;const go=async e=>{e.preventDefault();setBusy(true);setError('');try{await login(email,password);nav('/panel')}catch(e){setError(e.message)}finally{setBusy(false)}};return <div className="grid min-h-screen lg:grid-cols-2"><div className="noise grid-lines hidden bg-ink p-12 text-white lg:flex lg:flex-col lg:justify-between"><Logo light/><div><div className="text-xs font-black uppercase tracking-[.2em] text-electric">Control room</div><h1 className="mt-4 font-display text-6xl font-bold leading-[.95]">Semua arena.<br/>Satu kendali.</h1><p className="mt-6 max-w-md leading-7 text-slate-400">Kelola peserta, verifikasi dokumen, dan pantau performa kompetisi dari satu tempat.</p></div><p className="text-xs text-slate-500">Kreasi UNM 2026 Management System · 2026</p></div><div className="flex items-center justify-center p-5 sm:p-10"><form onSubmit={go} className="w-full max-w-md rounded-[30px] bg-white p-7 shadow-xl"><Logo/><h2 className="mt-10 font-display text-3xl font-bold">Selamat datang.</h2><p className="mt-2 text-sm text-slate-500">Masuk sebagai Super Admin atau PIC lomba.</p>{error&&<div className="mt-5 rounded-xl bg-rose-100 p-3 text-sm font-bold text-rose-700">{error}</div>}<div className="mt-7 grid gap-5"><Field label="Email"><input className="input" type="email" value={email} onChange={e=>setEmail(e.target.value)} required/></Field><Field label="Kata sandi"><input className="input" type="password" value={password} onChange={e=>setPassword(e.target.value)} required/></Field></div><button disabled={busy} className="btn-dark mt-7 w-full py-3.5">{busy?'Memeriksa...':'Masuk ke Dashboard'} <ArrowRight size={17}/></button><div className="mt-5 rounded-xl bg-slate-50 p-3 text-xs text-slate-500"><b>Akun demo:</b> admin@kreasiunm.id / password123<br/>PIC: pic@kreasiunm.id / password123</div><Link to="/" className="mt-6 block text-center text-sm font-bold text-slate-500">← Kembali ke website</Link></form></div></div>}

function Protected(){const {user}=useAuth();return user?<Outlet/>:<Navigate to="/login" replace/>}
function PanelLayout(){const {user,logout}=useAuth(),nav=useNavigate(),[open,setOpen]=useState(false);const links=[['/panel',LayoutDashboard,'Ringkasan'],['/panel/pendaftar',ClipboardCheck,'Pendaftar'],...(user.role==='super_admin'?[['/panel/lomba',Trophy,'Lomba'],['/panel/pic',UserCog,'Akun PIC']]:[])];const out=async()=>{await logout();nav('/login')};return <div className="min-h-screen bg-[#f3f4ef] lg:grid lg:grid-cols-[250px_1fr]"><aside className={`fixed inset-y-0 left-0 z-50 w-[250px] bg-ink p-5 text-white transition lg:sticky lg:top-0 lg:h-screen ${open?'translate-x-0':'-translate-x-full lg:translate-x-0'}`}><div className="flex items-center justify-between"><Logo light/><button onClick={()=>setOpen(false)} className="lg:hidden"><X/></button></div><div className="mt-10 rounded-2xl border border-white/10 bg-white/5 p-3"><div className="text-sm font-bold">{user.name}</div><div className="mt-1 text-xs text-slate-400">{user.role==='super_admin'?'Super Admin':`PIC · ${user.competition?.title||''}`}</div></div><nav className="mt-6 grid gap-2">{links.map(([to,Icon,label],i)=><NavLink end={i===0} to={to} onClick={()=>setOpen(false)} key={to} className={({isActive})=>`flex items-center gap-3 rounded-xl px-3 py-3 text-sm font-bold ${isActive?'bg-electric text-ink':'text-slate-400 hover:bg-white/5 hover:text-white'}`}><Icon size={18}/>{label}</NavLink>)}</nav><button onClick={out} className="absolute bottom-5 left-5 right-5 flex items-center gap-3 rounded-xl px-3 py-3 text-sm font-bold text-slate-400 hover:bg-white/5 hover:text-white"><LogOut size={18}/>Keluar</button></aside>{open&&<button aria-label="Tutup menu" onClick={()=>setOpen(false)} className="fixed inset-0 z-40 bg-black/40 lg:hidden"/>}<main className="min-w-0"><header className="sticky top-0 z-30 flex h-18 items-center justify-between border-b bg-[#f3f4ef]/90 px-5 backdrop-blur lg:px-8"><button onClick={()=>setOpen(true)} className="grid size-10 place-items-center rounded-xl bg-white lg:hidden"><Menu/></button><div className="hidden text-sm font-bold text-slate-500 lg:block">Kreasi UNM 2026 · Management System</div><Link to="/" target="_blank" className="btn-ghost text-sm">Lihat website <ArrowUpRight size={15}/></Link></header><div className="p-5 lg:p-8"><Outlet/></div></main></div>}

function PageHead({eyebrow,title,action}){return <div className="mb-7 flex flex-wrap items-end justify-between gap-4"><div><div className="text-xs font-black uppercase tracking-[.16em] text-blue-600">{eyebrow}</div><h1 className="mt-2 font-display text-3xl font-bold tracking-tight">{title}</h1></div>{action}</div>}
function Dashboard(){const {user}=useAuth(),[data,setData]=useState(null);useEffect(()=>{api('/manage/dashboard').then(setData)},[]);if(!data)return <Loader/>;const cards=[[Trophy,'Lomba aktif',data.competitions,'bg-blue-100 text-blue-700'],[Users,'Total pendaftar',data.registrations,'bg-violet-100 text-violet-700'],[Clock3,'Perlu diverifikasi',data.pending,'bg-amber-100 text-amber-700'],[WalletCards,'Estimasi transaksi',money(data.revenue),'bg-emerald-100 text-emerald-700']];return <><PageHead eyebrow="Overview" title={`Halo, ${user.name.split(' ')[0]}!`}/><div className="grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{cards.map(([Icon,label,value,cls])=><div key={label} className="rounded-3xl bg-white p-5"><span className={`grid size-11 place-items-center rounded-2xl ${cls}`}><Icon size={20}/></span><div className="mt-5 font-display text-2xl font-bold">{value}</div><div className="mt-1 text-sm text-slate-500">{label}</div></div>)}</div><div className="mt-7 rounded-3xl bg-white p-5 sm:p-7"><div className="flex items-center justify-between"><div><h2 className="font-display text-xl font-bold">Pendaftar terbaru</h2><p className="mt-1 text-sm text-slate-500">Aktivitas terkini di arena.</p></div><Link to="/panel/pendaftar" className="text-sm font-bold">Lihat semua →</Link></div><div className="mt-6 overflow-x-auto"><table className="w-full min-w-[620px] text-left text-sm"><thead className="text-xs uppercase text-slate-400"><tr><th className="pb-3">Peserta</th><th>Lomba</th><th>Sekolah</th><th>Status</th></tr></thead><tbody className="divide-y">{data.recent.map(r=><tr key={r.id}><td className="py-4"><b>{r.full_name}</b><div className="text-xs text-slate-400">{r.ticket_code}</div></td><td>{r.competition.title}</td><td>{r.school_name}</td><td><Status value={r.status}/></td></tr>)}</tbody></table></div></div></>}

function Registrations(){const [data,setData]=useState(null),[status,setStatus]=useState('all'),[search,setSearch]=useState(''),[selected,setSelected]=useState(null);const load=()=>{const q=new URLSearchParams({status,search});api(`/manage/registrations?${q}`).then(setData)};useEffect(()=>{const q=new URLSearchParams({status,search});const t=setTimeout(()=>api(`/manage/registrations?${q}`).then(setData),200);return()=>clearTimeout(t)},[status,search]);const open=async id=>setSelected(await api(`/manage/registrations/${id}`));const download=async()=>{const blob=await api('/manage/registrations/export');const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download='peserta-tervalidasi.csv';a.click();URL.revokeObjectURL(url)};return <><PageHead eyebrow="Verificator desk" title="Pendaftar" action={<button onClick={download} className="btn-dark"><Download size={16}/>Ekspor CSV</button>}/><div className="mb-5 flex flex-col gap-3 rounded-2xl bg-white p-3 sm:flex-row"><label className="relative flex-1"><Search size={17} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input className="input py-2 pl-10" placeholder="Nama, tiket, atau sekolah..." value={search} onChange={e=>setSearch(e.target.value)}/></label><select className="input py-2 sm:w-48" value={status} onChange={e=>setStatus(e.target.value)}><option value="all">Semua status</option><option value="pending">Menunggu</option><option value="approved">Diterima</option><option value="revision">Butuh revisi</option><option value="rejected">Ditolak</option></select></div>{!data?<Loader/>:data.data.length?<div className="overflow-hidden rounded-3xl bg-white"><div className="overflow-x-auto"><table className="w-full min-w-[760px] text-left text-sm"><thead className="bg-slate-50 text-xs uppercase text-slate-400"><tr><th className="p-4">Peserta</th><th>Lomba</th><th>Sekolah</th><th>Daftar</th><th>Status</th><th/></tr></thead><tbody className="divide-y">{data.data.map(r=><tr key={r.id} className="hover:bg-slate-50"><td className="p-4"><b>{r.full_name}</b><div className="text-xs text-slate-400">{r.ticket_code}</div></td><td>{r.competition.title}</td><td>{r.school_name}<div className="text-xs text-slate-400">Kelas {r.grade}</div></td><td>{formatDate(r.created_at)}</td><td><Status value={r.status}/></td><td className="p-4 text-right"><button onClick={()=>open(r.id)} className="btn-ghost py-2"><Eye size={15}/>Periksa</button></td></tr>)}</tbody></table></div></div>:<Empty title="Belum ada pendaftar"/>}{selected&&<VerifyModal item={selected} close={()=>setSelected(null)} saved={()=>{setSelected(null);load()}}/>}</>}
function VerifyModal({item,close,saved}){const [status,setStatus]=useState(item.status==='pending'?'approved':item.status),[note,setNote]=useState(item.review_note||''),[busy,setBusy]=useState(false),[error,setError]=useState('');const submit=async()=>{setBusy(true);setError('');try{await api(`/manage/registrations/${item.id}/review`,{method:'PATCH',body:JSON.stringify({status,review_note:note})});saved()}catch(e){setError(e.message)}finally{setBusy(false)}};const files=[['Kartu pelajar',item.student_card_path],['Surat delegasi',item.delegation_letter_path],['Pas foto',item.photo_path],['Bukti pembayaran',item.payment_proof_path]];return <div className="fixed inset-0 z-[60] overflow-y-auto bg-ink/70 p-3 backdrop-blur-sm sm:p-6"><div className="mx-auto max-w-4xl overflow-hidden rounded-[28px] bg-white"><div className="flex items-start justify-between border-b p-5 sm:p-7"><div><div className="text-xs font-bold text-blue-600">{item.ticket_code}</div><h2 className="mt-1 font-display text-2xl font-bold">{item.full_name}</h2><p className="text-sm text-slate-500">{item.competition.title}</p></div><button onClick={close} className="grid size-9 place-items-center rounded-full bg-slate-100"><X size={18}/></button></div><div className="grid gap-7 p-5 sm:p-7 lg:grid-cols-[1fr_300px]"><div><h3 className="font-display font-bold">Data peserta</h3><div className="mt-4 grid gap-x-6 gap-y-4 sm:grid-cols-2"><Info label="NISN" value={item.nisn}/><Info label="Email" value={item.email}/><Info label="WhatsApp" value={item.whatsapp}/><Info label="Kelas" value={item.grade}/><Info label="Sekolah" value={item.school_name}/><Info label="Guru pendamping" value={`${item.teacher_name} · ${item.teacher_contact}`}/>{item.mother_name&&<Info label="Nama ibu (Super Admin)" value={item.mother_name}/>}</div><h3 className="mt-8 font-display font-bold">Dokumen</h3><div className="mt-4 grid gap-3 sm:grid-cols-2">{files.filter(x=>x[1]).map(([label,path])=><a key={label} href={`${STORAGE}/${path}`} target="_blank" className="flex items-center gap-3 rounded-2xl border p-4 hover:border-ink"><span className="grid size-9 place-items-center rounded-xl bg-blue-50 text-blue-600"><FileCheck2 size={18}/></span><span className="text-sm font-bold">{label}</span><ArrowUpRight className="ml-auto" size={16}/></a>)}</div></div><aside className="rounded-2xl bg-slate-50 p-5"><h3 className="font-display font-bold">Keputusan verifikasi</h3><div className="mt-4 grid gap-2"><Choice value="approved" current={status} set={setStatus} label="Diterima" cls="peer-checked:bg-emerald-100 peer-checked:border-emerald-500"/><Choice value="revision" current={status} set={setStatus} label="Butuh revisi" cls="peer-checked:bg-violet-100 peer-checked:border-violet-500"/><Choice value="rejected" current={status} set={setStatus} label="Ditolak" cls="peer-checked:bg-rose-100 peer-checked:border-rose-500"/></div><label className="mt-5 block"><span className="label">Catatan {status!=='approved'&&'*'}</span><textarea className="input min-h-28 resize-none" value={note} onChange={e=>setNote(e.target.value)} placeholder="Jelaskan hasil pemeriksaan..."/></label>{error&&<p className="mt-3 text-xs font-bold text-rose-600">{error}</p>}<button onClick={submit} disabled={busy} className="btn-dark mt-5 w-full">{busy?'Menyimpan...':'Simpan Keputusan'}</button></aside></div></div></div>}
function Info({label,value}){return <div><div className="text-xs font-bold uppercase tracking-wider text-slate-400">{label}</div><div className="mt-1 text-sm font-bold">{value||'-'}</div></div>}
function Choice({value,current,set,label,cls}){return <label><input className="peer hidden" type="radio" name="status" checked={current===value} onChange={()=>set(value)}/><span className={`block cursor-pointer rounded-xl border border-slate-200 bg-white p-3 text-sm font-bold ${cls}`}>{label}</span></label>}

