function CompetitionsAdmin(){const [items,setItems]=useState([]),[form,setForm]=useState(null),load=()=>api('/manage/competitions').then(setItems);useEffect(()=>{load()},[]);const remove=async id=>{if(!confirm('Hapus lomba ini beserta seluruh pendaftarnya?'))return;await api(`/manage/competitions/${id}`,{method:'DELETE'});load()};return <><PageHead eyebrow="Content management" title="Manajemen Lomba" action={<button className="btn-dark" onClick={()=>setForm({...blankComp})}><Plus size={17}/>Buat lomba</button>}/><div className="grid gap-4 lg:grid-cols-2">{items.map(x=><div key={x.id} className="flex gap-4 rounded-3xl bg-white p-4"><img className="h-28 w-24 rounded-2xl object-cover" src={x.poster_url}/><div className="min-w-0 flex-1"><div className="text-xs font-bold text-blue-600">{x.category}</div><h3 className="mt-1 truncate font-display text-lg font-bold">{x.title}</h3><p className="mt-2 text-xs text-slate-500">{x.registrations_count} pendaftar · {formatDate(x.event_date)}</p><div className="mt-4 flex gap-2"><button onClick={()=>setForm(x)} className="btn-ghost py-1.5 text-xs"><Pencil size={13}/>Edit</button><button onClick={()=>remove(x.id)} className="btn-ghost py-1.5 text-xs text-rose-600"><Trash2 size={13}/>Hapus</button></div></div></div>)}</div>{form&&<CompetitionForm item={form} close={()=>setForm(null)} saved={()=>{setForm(null);load()}}/>}</>}
function CompetitionForm({item,close,saved}){const [data,setData]=useState({...item}),[busy,setBusy]=useState(false),[error,setError]=useState('');const set=(k,v)=>setData(d=>({...d,[k]:v}));const submit=async e=>{e.preventDefault();setBusy(true);setError('');try{const payload={...data,quota:Number(data.quota),fee:Number(data.fee),is_featured:!!data.is_featured,requirements:typeof data.requirements==='string'?data.requirements.split('\n').filter(Boolean):data.requirements,timeline:[{date:data.registration_start,label:'Pendaftaran dibuka'},{date:data.registration_end,label:'Pendaftaran ditutup'},{date:data.event_date,label:'Hari kompetisi'}]};await api(`/manage/competitions${item.id?`/${item.id}`:''}`,{method:item.id?'PUT':'POST',body:JSON.stringify(payload)});saved()}catch(e){setError(e.message)}finally{setBusy(false)}};return <div className="fixed inset-0 z-[60] overflow-y-auto bg-ink/70 p-3"><form onSubmit={submit} className="mx-auto my-4 max-w-3xl rounded-[28px] bg-white p-5 sm:p-7"><div className="flex justify-between"><h2 className="font-display text-2xl font-bold">{item.id?'Edit lomba':'Buat lomba baru'}</h2><button type="button" onClick={close}><X/></button></div>{error&&<p className="mt-4 rounded-xl bg-rose-100 p-3 text-sm font-bold text-rose-700">{error}</p>}<div className="mt-7 grid gap-5 sm:grid-cols-2"><Field label="Judul lomba"><input className="input" value={data.title} onChange={e=>set('title',e.target.value)} required/></Field><Field label="Kategori"><select className="input" value={data.category} onChange={e=>set('category',e.target.value)}><option>Akademik</option><option>Olahraga</option><option>Seni</option></select></Field><div className="sm:col-span-2"><Field label="Ringkasan"><input className="input" value={data.short_description} maxLength="300" onChange={e=>set('short_description',e.target.value)} required/></Field></div><div className="sm:col-span-2"><Field label="Deskripsi"><textarea className="input min-h-28" value={data.description} onChange={e=>set('description',e.target.value)} required/></Field></div><Field label="Kuota"><input className="input" type="number" min="1" value={data.quota} onChange={e=>set('quota',e.target.value)} required/></Field><Field label="Biaya (Rp)"><input className="input" type="number" min="0" value={data.fee} onChange={e=>set('fee',e.target.value)} required/></Field><Field label="Mulai pendaftaran"><input className="input" type="date" value={String(data.registration_start).slice(0,10)} onChange={e=>set('registration_start',e.target.value)} required/></Field><Field label="Tutup pendaftaran"><input className="input" type="date" value={String(data.registration_end).slice(0,10)} onChange={e=>set('registration_end',e.target.value)} required/></Field><Field label="Tanggal lomba"><input className="input" type="date" value={String(data.event_date).slice(0,10)} onChange={e=>set('event_date',e.target.value)} required/></Field><Field label="Lokasi"><input className="input" value={data.location} onChange={e=>set('location',e.target.value)} required/></Field><div className="sm:col-span-2"><Field label="URL poster (disarankan 1080 × 1350 px, rasio 4:5)"><input className="input" type="url" value={data.poster_url||''} onChange={e=>set('poster_url',e.target.value)}/></Field></div><div className="sm:col-span-2"><Field label="Syarat (satu per baris)"><textarea className="input min-h-24" value={Array.isArray(data.requirements)?data.requirements.join('\n'):data.requirements} onChange={e=>set('requirements',e.target.value)}/></Field></div><label className="flex items-center gap-2 text-sm font-bold"><input type="checkbox" checked={!!data.is_featured} onChange={e=>set('is_featured',e.target.checked)} className="size-4"/>Tampilkan sebagai unggulan</label></div><div className="mt-7 flex justify-end gap-3"><button type="button" className="btn-ghost" onClick={close}>Batal</button><button className="btn-dark" disabled={busy}>{busy?'Menyimpan...':'Simpan Lomba'}</button></div></form></div>}

function Pics(){const [items,setItems]=useState([]),[competitions,setCompetitions]=useState([]),[form,setForm]=useState(null),load=()=>api('/manage/pics').then(setItems);useEffect(()=>{load();api('/manage/competitions').then(setCompetitions)},[]);const remove=async id=>{if(!confirm('Hapus akun PIC ini?'))return;await api(`/manage/pics/${id}`,{method:'DELETE'});load()};return <><PageHead eyebrow="Access control" title="Akun PIC" action={<button onClick={()=>setForm({name:'',email:'',password:'',competition_id:''})} className="btn-dark"><Plus size={17}/>Tambah PIC</button>}/><div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">{items.map(x=><div className="rounded-3xl bg-white p-5" key={x.id}><div className="flex items-center gap-3"><span className="grid size-11 place-items-center rounded-2xl bg-violet-100 font-display font-bold text-violet-700">{x.name.slice(0,2).toUpperCase()}</span><div className="min-w-0"><h3 className="truncate font-bold">{x.name}</h3><p className="truncate text-xs text-slate-500">{x.email}</p></div></div><div className="mt-5 rounded-xl bg-slate-50 p-3 text-sm"><div className="text-xs text-slate-400">Ditugaskan ke</div><b>{x.competition?.title||'Belum ditugaskan'}</b></div><div className="mt-4 flex gap-2"><button onClick={()=>setForm({...x,password:''})} className="btn-ghost py-2 text-xs"><Pencil size={13}/>Edit</button><button onClick={()=>remove(x.id)} className="btn-ghost py-2 text-xs text-rose-600"><Trash2 size={13}/></button></div></div>)}</div>{form&&<PicForm item={form} competitions={competitions} close={()=>setForm(null)} saved={()=>{setForm(null);load()}}/>}</>}
function PicForm({item,competitions,close,saved}){const [data,setData]=useState(item),[error,setError]=useState(''),[busy,setBusy]=useState(false);const submit=async e=>{e.preventDefault();setBusy(true);try{await api(`/manage/pics${item.id?`/${item.id}`:''}`,{method:item.id?'PUT':'POST',body:JSON.stringify(data)});saved()}catch(e){setError(e.message)}finally{setBusy(false)}};return <div className="fixed inset-0 z-[60] grid place-items-center bg-ink/70 p-4"><form onSubmit={submit} className="w-full max-w-lg rounded-[28px] bg-white p-6"><div className="flex justify-between"><h2 className="font-display text-2xl font-bold">{item.id?'Edit PIC':'Tambah PIC'}</h2><button type="button" onClick={close}><X/></button></div>{error&&<p className="mt-4 rounded-xl bg-rose-100 p-3 text-sm font-bold text-rose-700">{error}</p>}<div className="mt-6 grid gap-4"><Field label="Nama"><input className="input" value={data.name} onChange={e=>setData({...data,name:e.target.value})} required/></Field><Field label="Email"><input className="input" type="email" value={data.email} onChange={e=>setData({...data,email:e.target.value})} required/></Field><Field label={item.id?'Kata sandi baru (opsional)':'Kata sandi'}><input className="input" type="password" minLength="8" value={data.password} onChange={e=>setData({...data,password:e.target.value})} required={!item.id}/></Field><Field label="Lomba yang dikelola"><select className="input" value={data.competition_id||''} onChange={e=>setData({...data,competition_id:e.target.value})} required><option value="">Pilih lomba</option>{competitions.map(x=><option key={x.id} value={x.id}>{x.title}</option>)}</select></Field></div><button className="btn-dark mt-6 w-full" disabled={busy}>{busy?'Menyimpan...':'Simpan Akun'}</button></form></div>}

function PersonalFields({prefix='', errors={}}) {
  const n = key => prefix ? `${prefix}[${key}]` : key
  const e = key => errors[prefix ? prefix.replaceAll('[','.').replaceAll(']','')+'.'+key : key]
  return <div className="grid gap-5 sm:grid-cols-2">
    <Field label="Nama lengkap *" error={e('full_name')}><input className="input" name={n('full_name')} required/></Field>
    <Field label="NISN (10 digit) *" error={e('nisn')}><input className="input" name={n('nisn')} inputMode="numeric" pattern="[0-9]{10}" maxLength="10" required/></Field>
    <Field label="Tempat lahir *" error={e('birth_place')}><input className="input" name={n('birth_place')} required/></Field>
    <Field label="Tanggal lahir *" error={e('birth_date')}><input className="input" name={n('birth_date')} type="date" required/></Field>
    <Field label="Kelas *" error={e('grade')}><select className="input" name={n('grade')} required><option value="">Pilih kelas</option><option>X</option><option>XI</option><option>XII</option></select></Field>
    <Field label="Nama ibu kandung *" error={e('mother_name')}><input className="input" name={n('mother_name')} required/><span className="mt-1 flex items-center gap-1 text-[11px] text-slate-400"><LockKeyhole size={11}/>Terenkripsi dan tidak terlihat oleh PIC.</span></Field>
  </div>
}

function TeamAwareRegistration(){
  const {slug}=useParams(),[item,setItem]=useState(null),[errors,setErrors]=useState({}),[busy,setBusy]=useState(false),[ticket,setTicket]=useState('')
  useEffect(()=>{api(`/competitions/${slug}`).then(setItem)},[slug])
  const submit=async e=>{e.preventDefault();setBusy(true);setErrors({});const form=new FormData(e.currentTarget);form.set('competition_id',item.id);form.set('consent',form.get('consent')?'1':'');try{const res=await api('/registrations',{method:'POST',body:form});setTicket(res.ticket_code);scrollTo(0,0)}catch(err){setErrors(err.errors||{general:[err.message]});scrollTo(0,0)}finally{setBusy(false)}}
  if(!item)return <Loader/>
  const isTeam=item.participation_type==='team', size=isTeam?item.team_size:1
  if(ticket)return <section className="min-h-[75vh] px-5 py-16"><div className="mx-auto max-w-xl rounded-[34px] bg-white p-8 text-center shadow-xl"><div className="mx-auto grid size-20 place-items-center rounded-full bg-electric"><TicketCheck size={38}/></div><h1 className="mt-6 font-display text-3xl font-bold">{isTeam?'Tim kamu resmi masuk arena!':'Kamu resmi masuk arena!'}</h1><p className="mt-3 text-slate-500">Pendaftaran telah kami terima. Simpan kode tiket ini untuk memantau proses verifikasi.</p><div className="mt-7 rounded-2xl border-2 border-dashed border-slate-200 bg-slate-50 p-5"><div className="text-xs font-bold uppercase tracking-widest text-slate-400">Kode Tiket</div><div className="mt-2 font-display text-2xl font-bold tracking-wider">{ticket}</div></div><Link to="/lacak" className="btn-dark mt-7 w-full">Lacak Status <ArrowRight size={17}/></Link></div></section>
  return <section className="px-5 py-10 lg:px-8"><div className="mx-auto max-w-4xl"><Link to={`/lomba/${slug}`} className="text-sm font-bold text-slate-500">← Kembali</Link><div className="mt-5"><div className="text-xs font-black uppercase tracking-[.2em] text-blue-600">Formulir pendaftaran</div><h1 className="mt-2 font-display text-3xl font-bold sm:text-5xl">Ambil tempatmu di arena.</h1><div className="mt-3 flex flex-wrap items-center gap-2 text-slate-500"><span>{item.title} · {money(item.fee)}</span><span className="rounded-full bg-cyan-100 px-3 py-1 text-xs font-bold text-cyan-800">{isTeam?`Tim · ${size} orang`:'Individu'}</span></div></div>{errors.general&&<div className="mt-6 rounded-2xl bg-rose-100 p-4 font-bold text-rose-700">{errors.general[0]}</div>}
    <form onSubmit={submit} className="mt-8 grid gap-6">
      <FormSection number="01" title="Kontak pendaftaran" text={isTeam?'Kontak koordinator yang dapat dihubungi panitia.':'Email dan nomor aktif peserta.'}><div className="grid gap-5 sm:grid-cols-2"><Field label="Email aktif *" error={errors.email}><input className="input" name="email" type="email" required/></Field><Field label="Nomor WhatsApp *" error={errors.whatsapp}><input className="input" name="whatsapp" inputMode="tel" required/></Field></div></FormSection>
      {isTeam ? <FormSection number="02" title={`Data ${size} anggota tim`} text="Jumlah anggota telah ditentukan pengelola dan wajib diisi lengkap."><div className="grid gap-6">{Array.from({length:size},(_,i)=><div key={i} className="rounded-3xl border border-slate-200 bg-slate-50 p-5"><div className="mb-5 flex items-center gap-3"><span className="grid size-9 place-items-center rounded-full bg-ink font-display font-bold text-white">{i+1}</span><div><h3 className="font-display font-bold">Anggota {i+1}{i===0?' · Koordinator':''}</h3><p className="text-xs text-slate-500">Identitas dan dokumen pribadi</p></div></div><PersonalFields prefix={`members[${i}]`} errors={errors}/><div className="mt-5 grid gap-5 sm:grid-cols-2"><FileInput name={`member_student_cards[${i}]`} label="Kartu pelajar aktif *" accept=".jpg,.jpeg,.png,.pdf" error={errors[`member_student_cards.${i}`]}/><FileInput name={`member_photos[${i}]`} label="Pas foto resmi *" accept=".jpg,.jpeg,.png" error={errors[`member_photos.${i}`]}/></div></div>)}</div></FormSection> : <FormSection number="02" title="Data diri" text="Pastikan sesuai dokumen resmi."><PersonalFields errors={errors}/><div className="mt-5 grid gap-5 sm:grid-cols-2"><FileInput name="student_card" label="Kartu pelajar aktif *" accept=".jpg,.jpeg,.png,.pdf" error={errors.student_card}/><FileInput name="photo" label="Pas foto resmi *" accept=".jpg,.jpeg,.png" error={errors.photo}/></div></FormSection>}
      <FormSection number="03" title="Sekolah & administrasi" text="Informasi bersama untuk validasi delegasi."><div className="grid gap-5 sm:grid-cols-2">{isTeam&&<Field label="Nama tim *" error={errors.team_name}><input className="input" name="team_name" required/></Field>}<Field label="Asal sekolah *" error={errors.school_name}><input className="input" name="school_name" required/></Field><Field label="Nama guru pendamping *" error={errors.teacher_name}><input className="input" name="teacher_name" required/></Field><Field label="Kontak guru *" error={errors.teacher_contact}><input className="input" name="teacher_contact" inputMode="tel" required/></Field><Field label="Kode sekolah (opsional)" error={errors.school_code}><input className="input" name="school_code" placeholder="Untuk jalur undangan"/></Field><Field label="Kategori peserta (opsional)" error={errors.participant_category}><input className="input" name="participant_category"/></Field></div><div className="mt-5 grid gap-5 sm:grid-cols-2"><FileInput name="delegation_letter" label="Surat delegasi resmi *" accept=".jpg,.jpeg,.png,.pdf" error={errors.delegation_letter}/>{Number(item.fee)>0&&<FileInput name="payment_proof" label="Bukti pembayaran" accept=".jpg,.jpeg,.png,.pdf" error={errors.payment_proof}/>}</div></FormSection>
      <div className="rounded-3xl bg-ink p-6 text-white"><label className="flex cursor-pointer items-start gap-3"><input type="checkbox" name="consent" required className="mt-1 size-5 accent-[#b8ff2c]"/><span className="text-sm leading-6 text-slate-300">Saya menyetujui penggunaan data seluruh anggota untuk proses pendaftaran dan verifikasi serta memahami data sensitif dijaga kerahasiaannya.</span></label><button disabled={busy} className="btn-primary mt-6 w-full py-4 disabled:opacity-60">{busy?'Mengirim pendaftaran...':'Kirim Pendaftaran'} {!busy&&<ArrowRight size={18}/>}</button></div>
    </form></div></section>
}

function FormatModal({competition,close,saved}){
  const existingType=competition.participation_type==='team'?'team':'individual'
  const existingSize=existingType==='team'?Math.max(2,Number(competition.team_size??2)):1
  const existingOfficials=existingType==='team'?Math.max(0,Number(competition.official_count??0)):0
  const [type,setType]=useState(existingType),[size,setSize]=useState(existingSize),[officials,setOfficials]=useState(existingOfficials),[error,setError]=useState(''),[busy,setBusy]=useState(false)
  const submit=async e=>{e.preventDefault();setBusy(true);setError('');try{await api(`/manage/competitions/${competition.id}/format`,{method:'PATCH',body:JSON.stringify({participation_type:type,team_size:type==='team'?Number(size):1,official_count:type==='team'?Number(officials):0})});saved()}catch(e){setError(e.message)}finally{setBusy(false)}}
  const existingSummary=existingType==='team'?`Tim · ${existingSize} anggota · ${existingOfficials} official`:'Individu'
  return <div className="fixed inset-0 z-[70] grid place-items-center bg-ink/70 p-4"><form onSubmit={submit} className="w-full max-w-md rounded-[28px] bg-white p-6"><div className="flex items-start justify-between"><div><div className="text-xs font-bold uppercase tracking-wider text-blue-600">Format peserta</div><h2 className="mt-1 font-display text-2xl font-bold">{competition.title}</h2></div><button type="button" onClick={close}><X/></button></div><div className="mt-5 rounded-2xl bg-blue-50 p-4"><div className="text-xs font-bold uppercase tracking-wider text-blue-600">Format saat ini</div><div className="mt-1 font-bold text-slate-800">{existingSummary}</div></div>{error&&<p className="mt-4 rounded-xl bg-rose-100 p-3 text-sm font-bold text-rose-700">{error}</p>}<div className="mt-6 grid grid-cols-2 gap-3">{[['individual','Individu'],['team','Tim']].map(([value,label])=><label key={value} className={`cursor-pointer rounded-2xl border-2 p-4 text-center font-bold ${type===value?'border-ink bg-electric':'border-slate-200'}`}><input hidden type="radio" checked={type===value} onChange={()=>setType(value)}/>{label}</label>)}</div>{type==='team'&&<div className="mt-5 grid gap-5 sm:grid-cols-2"><Field label="Jumlah anggota tim"><input className="input" type="number" min="2" max="20" value={size} onChange={e=>setSize(e.target.value)} required/></Field><Field label="Jumlah official"><input className="input" type="number" min="0" max="20" value={officials} onChange={e=>setOfficials(e.target.value)} required/></Field><p className="text-xs text-slate-500 sm:col-span-2">Nilai sebelumnya otomatis dimuat. Form pendaftaran akan mengikuti jumlah terbaru.</p></div>}<button className="btn-dark mt-6 w-full" disabled={busy}>{busy?'Menyimpan...':'Perbarui Format'}</button></form></div>
}

function NotificationManager(){
  const {user}=useAuth(),allowed=user.permissions?.includes('notifications.manage'),canGlobal=user.role==='super_admin'||user.permissions?.includes('competitions.manage')
  const [competitions,setCompetitions]=useState([]),[notifications,setNotifications]=useState([]),[competitionId,setCompetitionId]=useState(canGlobal?'':String(user.competition_id||'')),[title,setTitle]=useState(''),[message,setMessage]=useState(''),[busy,setBusy]=useState(false),[error,setError]=useState('')
  const load=()=>Promise.all([api('/manage/competitions'),api('/manage/notifications')]).then(([competitionData,notificationData])=>{setCompetitions(competitionData);setNotifications(notificationData);if(!canGlobal&&!competitionId&&competitionData[0])setCompetitionId(String(competitionData[0].id))})
  useEffect(()=>{if(!allowed)return;Promise.all([api('/manage/competitions'),api('/manage/notifications')]).then(([competitionData,notificationData])=>{setCompetitions(competitionData);setNotifications(notificationData);if(!canGlobal)setCompetitionId(current=>current||String(competitionData[0]?.id||''))}).catch(()=>{})},[allowed,canGlobal])
  if(!allowed)return null
  const submit=async event=>{event.preventDefault();setBusy(true);setError('');try{await api('/manage/notifications',{method:'POST',body:JSON.stringify({competition_id:competitionId?Number(competitionId):null,title,message})});setTitle('');setMessage('');await load()}catch(e){setError(e.message)}finally{setBusy(false)}}
  const remove=async notification=>{if(!confirm(`Hapus notifikasi “${notification.title}”?`))return;await api(`/manage/notifications/${notification.id}`,{method:'DELETE'});load()}
  return <section className="mt-7 rounded-3xl bg-white p-5 sm:p-7"><div className="flex items-start gap-3"><span className="grid size-11 shrink-0 place-items-center rounded-2xl bg-violet-100 text-violet-700"><Megaphone size={21}/></span><div><h2 className="font-display text-xl font-bold">Notifikasi Peserta</h2><p className="mt-1 text-sm text-slate-500">Kirim informasi yang akan muncul di dashboard peserta setelah login.</p></div></div><form onSubmit={submit} className="mt-6 grid gap-4"><div className="grid gap-4 sm:grid-cols-2"><Field label="Tujuan notifikasi"><select className="input" value={competitionId} onChange={e=>setCompetitionId(e.target.value)} required={!canGlobal}>{canGlobal&&<option value="">Semua peserta</option>}{competitions.map(competition=><option key={competition.id} value={competition.id}>{competition.title}</option>)}</select></Field><Field label="Judul"><input className="input" value={title} maxLength="160" onChange={e=>setTitle(e.target.value)} placeholder="Contoh: Perubahan Jadwal" required/></Field></div><Field label="Isi notifikasi"><textarea className="input min-h-28" value={message} maxLength="5000" onChange={e=>setMessage(e.target.value)} placeholder="Tuliskan informasi untuk peserta..." required/></Field>{error&&<p className="rounded-xl bg-rose-100 p-3 text-sm font-bold text-rose-700">{error}</p>}<div className="flex justify-end"><button className="btn-dark" disabled={busy}><Send size={16}/>{busy?'Mengirim...':'Kirim Notifikasi'}</button></div></form><div className="mt-7 border-t pt-6"><h3 className="font-display font-bold">Notifikasi terkirim</h3>{notifications.length?<div className="mt-4 grid gap-3">{notifications.map(notification=><article key={notification.id} className="flex items-start justify-between gap-4 rounded-2xl bg-slate-50 p-4"><div><div className="flex flex-wrap items-center gap-2"><b>{notification.title}</b><span className="rounded-full bg-blue-100 px-2 py-0.5 text-xs font-bold text-blue-700">{notification.competition?.title||'Semua peserta'}</span></div><p className="mt-2 whitespace-pre-line text-sm leading-6 text-slate-600">{notification.message}</p><p className="mt-2 text-xs text-slate-400">{notification.author?.name} · {formatDateTime(notification.published_at)}</p></div><button onClick={()=>remove(notification)} className="btn-ghost shrink-0 py-2 text-rose-600" title="Hapus notifikasi"><Trash2 size={15}/></button></article>)}</div>:<p className="mt-3 text-sm text-slate-400">Belum ada notifikasi yang dikirim.</p>}</div></section>
}

