function VerifyModalV2({item,close,saved}){const [status,setStatus]=useState(item.status==='pending'?'approved':item.status),[note,setNote]=useState(item.review_note||''),[busy,setBusy]=useState(false),[error,setError]=useState('');const submit=async()=>{setBusy(true);setError('');try{await api(`/manage/registrations/${item.id}/review`,{method:'PATCH',body:JSON.stringify({status,review_note:note})});saved()}catch(e){setError(e.message)}finally{setBusy(false)}};const shared=[['Surat delegasi',item.delegation_letter_path],['Bukti pembayaran',item.payment_proof_path]];const isTeam=item.competition.participation_type==='team';return <div className="fixed inset-0 z-[60] overflow-y-auto bg-ink/70 p-3 backdrop-blur-sm sm:p-6"><div className="mx-auto max-w-5xl overflow-hidden rounded-[28px] bg-white"><div className="flex items-start justify-between border-b p-5 sm:p-7"><div><div className="text-xs font-bold text-blue-600">{item.ticket_code}</div><h2 className="mt-1 font-display text-2xl font-bold">{item.team_name||item.full_name}</h2><p className="text-sm text-slate-500">{item.competition.title} · {isTeam?`${item.members.length} anggota`:'Individu'}</p></div><button onClick={close} className="grid size-9 place-items-center rounded-full bg-slate-100"><X size={18}/></button></div><div className="grid gap-7 p-5 sm:p-7 lg:grid-cols-[1fr_300px]"><div><h3 className="font-display font-bold">Data pendaftaran</h3><div className="mt-4 grid gap-x-6 gap-y-4 sm:grid-cols-2"><Info label="Email koordinator" value={item.email}/><Info label="WhatsApp" value={item.whatsapp}/><Info label="Sekolah" value={item.school_name}/><Info label="Guru pendamping" value={`${item.teacher_name} · ${item.teacher_contact}`}/></div>{isTeam?<><h3 className="mt-8 font-display font-bold">Anggota tim</h3><div className="mt-4 grid gap-4">{item.members.map(m=><div key={m.id} className="rounded-2xl border p-4"><div className="flex items-center gap-3"><span className="grid size-8 place-items-center rounded-full bg-ink text-xs font-bold text-white">{m.member_order}</span><div><b>{m.full_name}</b><p className="text-xs text-slate-500">NISN {m.nisn} · Kelas {m.grade}</p></div></div><div className="mt-3 flex flex-wrap gap-2"><a target="_blank" href={`${STORAGE}/${m.student_card_path}`} className="btn-ghost py-1.5 text-xs"><FileCheck2 size={13}/>Kartu pelajar</a><a target="_blank" href={`${STORAGE}/${m.photo_path}`} className="btn-ghost py-1.5 text-xs"><Eye size={13}/>Pas foto</a></div>{m.mother_name&&<div className="mt-3 text-xs"><span className="text-slate-400">Nama ibu: </span><b>{m.mother_name}</b></div>}</div>)}</div></>:<div className="mt-6 grid gap-x-6 gap-y-4 sm:grid-cols-2"><Info label="Nama" value={item.full_name}/><Info label="NISN" value={item.nisn}/><Info label="Kelas" value={item.grade}/>{item.mother_name&&<Info label="Nama ibu (Super Admin)" value={item.mother_name}/>}<a target="_blank" href={`${STORAGE}/${item.student_card_path}`} className="btn-ghost text-sm">Kartu pelajar</a><a target="_blank" href={`${STORAGE}/${item.photo_path}`} className="btn-ghost text-sm">Pas foto</a></div>}<h3 className="mt-8 font-display font-bold">Dokumen bersama</h3><div className="mt-4 flex flex-wrap gap-3">{shared.filter(x=>x[1]).map(([label,path])=><a key={label} href={`${STORAGE}/${path}`} target="_blank" className="btn-ghost text-sm"><FileCheck2 size={16}/>{label}</a>)}</div></div><aside className="rounded-2xl bg-slate-50 p-5"><h3 className="font-display font-bold">Keputusan verifikasi</h3><div className="mt-4 grid gap-2"><Choice value="approved" current={status} set={setStatus} label="Diterima" cls="peer-checked:bg-emerald-100 peer-checked:border-emerald-500"/><Choice value="revision" current={status} set={setStatus} label="Butuh revisi" cls="peer-checked:bg-violet-100 peer-checked:border-violet-500"/><Choice value="rejected" current={status} set={setStatus} label="Ditolak" cls="peer-checked:bg-rose-100 peer-checked:border-rose-500"/></div><label className="mt-5 block"><span className="label">Catatan {status!=='approved'&&'*'}</span><textarea className="input min-h-28 resize-none" value={note} onChange={e=>setNote(e.target.value)}/></label>{error&&<p className="mt-3 text-xs font-bold text-rose-600">{error}</p>}<button onClick={submit} disabled={busy} className="btn-dark mt-5 w-full">{busy?'Menyimpan...':'Simpan Keputusan'}</button></aside></div></div></div>}

function NavbarParticipant(){const [open,setOpen]=useState(false),{user}=useAuth(),loc=useLocation();useEffect(()=>setOpen(false),[loc.pathname]);const dashboard=user?.role==='participant'?'/peserta':'/panel';return <header className="sticky top-0 z-50 border-b border-black/5 bg-[#f5f6f2]/90 backdrop-blur-xl"><div className="mx-auto flex h-18 max-w-7xl items-center justify-between px-5 lg:px-8"><Logo/><nav className="hidden items-center gap-7 text-sm font-bold md:flex"><NavLink to="/" className={({isActive})=>isActive?'text-ink':'text-slate-500 hover:text-ink'}>Beranda</NavLink><NavLink to="/lomba" className={({isActive})=>isActive?'text-ink':'text-slate-500 hover:text-ink'}>Jelajah Lomba</NavLink></nav><div className="hidden md:block">{user?<Link to={dashboard} className="btn-dark"><LayoutDashboard size={16}/>{user.role==='participant'?'Dashboard Peserta':'Dashboard Pengelola'}</Link>:<Link to="/login" className="btn-dark">Login <ArrowRight size={16}/></Link>}</div><button onClick={()=>setOpen(!open)} className="grid size-10 place-items-center rounded-xl bg-white md:hidden">{open?<X/>:<Menu/>}</button></div>{open&&<div className="border-t bg-white p-5 md:hidden"><div className="grid gap-2 font-bold"><Link className="rounded-xl p-3" to="/">Beranda</Link><Link className="rounded-xl p-3" to="/lomba">Jelajah Lomba</Link><Link className="btn-dark mt-2" to={user?dashboard:'/login'}>{user?'Dashboard':'Login'}</Link></div></div>}</header>}
