const HERO_FALLBACK={badge:'Musim kompetisi 2026',title_primary:'YOUR TALENT.',title_accent:'YOUR ARENA.',description:'Daftar sekali, lalu pantau verifikasi dan revisi data langsung dari dashboard peserta.',primary_button_label:'Temukan Lomba',primary_button_url:'/lomba',secondary_button_label:'Masuk Dashboard',secondary_button_url:'/login',hashtag:'#BERANIUNGGUL',slide_interval:5,slides:[]}
