  const [items,setItems]=useState([]),[form,setForm]=useState(null),[format,setFormatModal]=useState(null),[picModal,setPicModal]=useState(null),[guideModal,setGuideModal]=useState(null),[downloadsModal,setDownloadsModal]=useState(null),[generalDownloads,setGeneralDownloads]=useState(null),[slotSetup,setSlotSetup]=useState(false)
