    {slotSetup&&<SlotSetupModal close={()=>setSlotSetup(false)} next={({slots,timelineCount})=>{setSlotSetup(false);setForm({...blankComp,pic_slots:slots,timeline:Array.from({length:timelineCount},()=>({label:'',type:'single',date:'',start_date:'',end_date:''}))})}}/>}
