    {guideModal&&<GuideManagementModal competition={guideModal} close={()=>setGuideModal(null)} saved={()=>{setGuideModal(null);load()}}/>}
    {downloadsModal&&<CompetitionDownloadsModal competition={downloadsModal} close={()=>setDownloadsModal(null)} saved={()=>{setDownloadsModal(null);load()}}/>}
    {generalDownloads!==null&&<CompetitionDownloadsModal competition={{downloadable_documents:generalDownloads}} endpoint="/manage/general-documents" heading="Dokumen Umum" close={()=>setGeneralDownloads(null)} saved={()=>setGeneralDownloads(null)}/>} 
    {format&&<FormatModal competition={format} close={()=>setFormatModal(null)} saved={()=>{setFormatModal(null);load()}}/>}
