  const submit=async event=>{event.preventDefault();setBusy(true);setError('');try{await api(`/manage/roles${role?`/${role.id}`:''}`,{method:role?'PUT':'POST',body:JSON.stringify({name,permissions})});saved()}catch(e){setError(e.message)}finally{setBusy(false)}}
